const componentGroupTotal = (
  groupItems: Item[],
  customer: Customer,
): number => {
  const groupBase = componentGroupBase(groupItems);
  return (
    groupBase +
    surcharge(groupBase, isNewcomer(customer), NEWCOMER_PER_ITEM_SURCHARGE_RATE)
  );
};

const componentsTotal = (items: Item[], customer: Customer): number => {
  const groups = groupByType(items);
  return [...groups.values()].reduce(
    (sum, groupItems) => sum + componentGroupTotal(groupItems, customer),
    0,
  );
};

const nonComponentsTotal = (items: Item[], customer: Customer): number =>
  items.reduce((sum, item) => sum + premiumForItem(item, customer), 0);

export const quote = (input: QuoteInput): { premium: number } => {
  const components = input.items.filter(isComponent);
  const nonComponents = input.items.filter((item) => !isComponent(item));
  const itemsTotal =
    nonComponentsTotal(nonComponents, input.customer) +
    componentsTotal(components, input.customer);
  return { premium: Math.ceil(itemsTotal + PROCESSING_FEE) };
};
